import Autocomplete from '@mui/material/Autocomplete';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Card from '@mui/material/Card';
import CardContent from '@mui/material/CardContent';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
import Cookies from 'js-cookie';
import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { setUser } from '../store/auth.js';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { DesktopDatePicker } from '@mui/x-date-pickers/DesktopDatePicker';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import Paper from '@mui/material/Paper';
import Table from '@mui/material/Table';
import TableBody from '@mui/material/TableBody';
import TableCell from '@mui/material/TableCell';
import TableContainer from '@mui/material/TableContainer';
import TableHead from '@mui/material/TableHead';
import TableRow from '@mui/material/TableRow';
import dayjs from 'dayjs';
import { default as ReactSelect } from 'react-select';
import Option from './Option.js';

let users = [];

const InitialForm = {
  label: '',
  icon: '',
};
var d = {
  data: [
    {
      _id: '',
      transactions: [
        {
          amount: '',
          description: '',
          date: '',
          category: '',
          _id: '',
        },
      ],
    },
  ],
};

const icons = ['User'];

export default function BillForm() {
  const logged_user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const token = Cookies.get('token');
  const [form, setForm] = useState(InitialForm);
  const [filters, setFilter] = useState([]);
  const [data, setData] = useState([]);

  async function getUserList() {
    const token = Cookies.get('token');
    console.log('Hello');
    const res = await fetch(`${process.env.REACT_APP_API_URL}/user/all`, {
      method: 'GET',
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });
    console.log('Hey response', res);
    const users = await res.json();
    console.log(`Response i ${JSON.stringify(users)}`);
    setData(users);
  }

  //   useEffect(() => {
  //     // call api or anything
  //     // console.log('loading bill form');
  //     // users = getUserList();
  //     // console.log('Inside useEffect users: ', users);
  //   });

  useEffect(() => {
    getUserList();
  }, []);

  function generateOptions() {
    console.log('Data', data);
    let user_list = data.all_users || [];
    let final_list = [];
    console.log('User List:' + user_list);
    user_list.forEach((user) => {
      if (user._id != logged_user._id) {
        let data = {
          value: user._id,
          label: user.email,
        };
        final_list.push(data);
      }
    });
    console.log('Final List: ' + final_list);
    return final_list;
    // let q = [
    //   { value: 'ocean1', label: 'Ocean' },
    //   { value: 'blue', label: 'Blue' },
    //   { value: 'purple', label: 'Purple' },
    //   { value: 'red', label: 'Red' },
    //   { value: 'orange', label: 'Orange' },
    //   { value: 'yellow', label: 'Yellow' },
    //   { value: 'green', label: 'Green' },
    //   { value: 'forest', label: 'Forest' },
    //   { value: 'slate', label: 'Slate' },
    //   { value: 'silver', label: 'Silver' },
    // ];
    // return q;
  }

  // function reload(res) {
  //   if (res.ok) {
  //     setForm(InitialForm);
  //     fetchTransctions();
  //   }
  // }

  async function create() {
    console.log('Inside Create', form);
    try {
      const res = await fetch(`${process.env.REACT_APP_API_URL}/split`, {
        method: 'POST',
        body: JSON.stringify(form),
        headers: {
          'content-type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
      });
      // reload(res);
      alert('Successfully updated.');
    } catch (error) {
      alert('Failed to create a bill');
    }
  }

  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value });
  }

  function handleDropdown(newValue) {
    console.log('Innside handleDropdown ', newValue);
    setForm({ ...form, userList: newValue });
  }

  function handleDate(newValue) {
    setForm({ ...form, date: newValue });
  }

  function handleCategory(newValue) {
    setForm({ ...form, category: newValue });
  }

  async function handleSubmit(e) {
    e.preventDefault();
    create();
  }

  function categoryName(name) {
    return name ? name.toUpperCase() : '';
  }

  function formatDate(date) {
    console.log(date);
    if (date == undefined) {
      return '';
    }
    return dayjs(date).format('DD MMM, YYYY');
  }

  const Categories = [
    { label: 'All' },
    { label: 'Travel' },
    { label: 'Shopping' },
    { label: 'Investment' },
    { label: 'Misc' },
  ];

  const colourOptions = generateOptions();

  //   const colourStyles = {
  //     control: (styles) => ({ ...styles, left: 100 }),
  //   };

  return (
    <Container>
      <Card sx={{ minWidth: 275, marginTop: 10 }}>
        <CardContent sx={{ height: 175, position: 'absolute' }}>
          <Typography variant='h4'>Bills Split</Typography>
          <Typography variant='h6'>Add New Transaction</Typography>
          <Box
            component='form'
            onSubmit={handleSubmit}
            sx={{ display: 'flex' }}
          >
            <TextField
              sx={{ marginRight: 5 }}
              id='outlined-basic'
              label='Amount'
              type='number'
              size='small'
              name='amount'
              variant='outlined'
              value={form.amount}
              onChange={handleChange}
            />
            <TextField
              sx={{ marginRight: 5 }}
              id='outlined-basic'
              label='Description'
              size='small'
              name='description'
              variant='outlined'
              value={form.description}
              onChange={handleChange}
            />
            <LocalizationProvider dateAdapter={AdapterDayjs}>
              <DesktopDatePicker
                label='Transaction Date'
                inputFormat='MM/DD/YYYY'
                value={form.date}
                onChange={handleDate}
                renderInput={(params) => (
                  <TextField sx={{ marginRight: 5 }} size='small' {...params} />
                )}
              />
            </LocalizationProvider>

            <div style={{ width: 300 }}>
              <ReactSelect
                // styles={colourStyles}
                options={colourOptions}
                // onChange={(event, newValue) => {
                //   setForm({ ...form, userList: newValue });
                // }}
                isMulti
                closeMenuOnSelect={false}
                hideSelectedOptions={false}
                components={{
                  Option,
                }}
                onChange={handleDropdown}
                allowSelectAll={true}
                value={form.optionSelected}
              />
            </div>

            {/* {editTransaction.amount !== undefined && (
            <Button type='submit' variant='secondary'>
              Update
            </Button>
          )} */}

            <Button
              type='submit'
              variant='contained'
              style={{ marginLeft: 20, position: 'absolute', left: 1100 }}
            >
              Submit
            </Button>
          </Box>
        </CardContent>
      </Card>
    </Container>
  );
}
